/* Brand colors pulled from each company's own logo (ShowMojo's blue mark, Tenant
   Turner's orange mark) so switching accounts is visually obvious, not just a label change. */
const BRANDS = [
  {key:"SM", name:"ShowMojo", logo:"data:image/webp;base64,",
    theme:{blue:"#115FCE", blueLight:"#eaf2fd", chart:"#115FCE"}},
  {key:"TT", name:"Tenant Turner", logo:"data:image/png;base64,",
    theme:{blue:"#E85300", blueLight:"#fff1e6", chart:"#E85300"}}
];
function applyTheme(brandKey){
  const b = BRANDS.find(x=>x.key===brandKey) || BRANDS[0];
  const root = document.documentElement.style;
  root.setProperty("--blue", b.theme.blue);
  root.setProperty("--blue-light", b.theme.blueLight);
}
const METRIC_ORDER = ["rpcConnectRate","rpcToDemoRate","calls","rpcs","contacts","emailsSent","emailsOpened",
  "demosSet","scheduled","held","showingRate","closedWon","saleConversionRate","arr"];
const METRIC_LABEL = {
  rpcConnectRate:"RPC Connect Rate", rpcToDemoRate:"RPC to Demo Conversion Rate", calls:"Calls Placed",
  rpcs:"RPCs", contacts:"Contacts", emailsSent:"Emails Sent", emailsOpened:"Emails Opened",
  demosSet:"Demos Set", scheduled:"Scheduled To Show", held:"Held Demo", showingRate:"Showing Rate",
  closedWon:"Closed Won", saleConversionRate:"Sale Conversion Rate", arr:"ARR"
};
const RATE_METRICS = new Set(["rpcConnectRate","rpcToDemoRate","showingRate","saleConversionRate"]);
const MONEY_METRICS = new Set(["arr"]);

/* ---------------- Storage ---------------- */
const LS = {
  extra: b => `bdr_dash_extra_${b}`,
  ui: "bdr_dash_ui"
};
function loadJSON(key, fallback){ try{ const v = localStorage.getItem(key); return v? JSON.parse(v): fallback; }catch(e){ return fallback; } }
function saveJSON(key, val){ localStorage.setItem(key, JSON.stringify(val)); }

function getExtraRows(brand){ return loadJSON(LS.extra(brand), []); }
function setExtraRows(brand, rows){ saveJSON(LS.extra(brand), rows); }

/* ---------------- Row model: [date, bdrIdx, calls, rpcs, contacts, emailsSent, emailsOpened, demosSet, scheduled, held, closedWon, arr] ---------------- */
let ROWS_CACHE = {};
function getAllRows(brand){
  if(ROWS_CACHE[brand]) return ROWS_CACHE[brand];
  const src = EMBEDDED[brand];
  const bdrs = src.bdrs;
  const rows = src.rows.map(r => ({
    date:r[0], bdr:bdrs[r[1]], calls:r[2], rpcs:r[3], contacts:r[4], emailsSent:r[5], emailsOpened:r[6],
    demosSet:r[7], scheduled:r[8], held:r[9], closedWon:r[10], arr:r[11]
  }));
  const extra = getExtraRows(brand);
  const all = rows.concat(extra);
  all.sort((a,b)=> a.date < b.date ? -1 : a.date > b.date ? 1 : 0);
  ROWS_CACHE[brand] = all;
  return all;
}
function invalidateCache(brand){ delete ROWS_CACHE[brand]; }

function allBdrs(brand){
  const set = new Set();
  getAllRows(brand).forEach(r=>set.add(r.bdr));
  return Array.from(set).sort();
}

/* ---------------- Date helpers ---------------- */
function todayStr(){
  const d = new Date();
  return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0")+"-"+String(d.getDate()).padStart(2,"0");
}
function currentMonthKey(){ return todayStr().slice(0,7); }
function parseDate(s){ const [y,m,d]=s.split("-").map(Number); return new Date(y, m-1, d); }
function fmtDate(s){ const d=parseDate(s); return d.toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}); }
function mondayOf(dateStr){
  const d = parseDate(dateStr);
  const dow = d.getDay(); // 0 Sun .. 6 Sat
  const diff = (dow === 0) ? 6 : dow - 1;
  d.setDate(d.getDate() - diff);
  return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0")+"-"+String(d.getDate()).padStart(2,"0");
}
function weekLabel(mondayStr){ return "Week of " + fmtDate(mondayStr); }
function monthKeyOf(dateStr){ return dateStr.slice(0,7); }
function monthLabel(mKey){
  const [y,m]=mKey.split("-").map(Number);
  return new Date(y,m-1,1).toLocaleDateString("en-US",{month:"long",year:"numeric"});
}
function networkDays(start, end){
  let count=0; const d=new Date(start);
  while(d<=end){ const dow=d.getDay(); if(dow!==0 && dow!==6) count++; d.setDate(d.getDate()+1); }
  return count;
}
function monthProration(mKey){
  const [y,m]=mKey.split("-").map(Number);
  const monthStart = new Date(y,m-1,1);
  const monthEnd = new Date(y,m,0);
  const cur = currentMonthKey();
  if(mKey > cur) return 0;
  if(mKey < cur) return 1;
  const today = new Date(); today.setHours(0,0,0,0);
  const denom = networkDays(monthStart, monthEnd);
  const num = networkDays(monthStart, today);
  return denom? num/denom : 0;
}
// Same idea as monthProration, but for a single week or day: what fraction of that
// business day/week's parent month's business days does it represent (capped at today
// for a week/day still in progress, 0 for one entirely in the future).
function weekTargetFraction(monday){
  const mKey = monthKeyOf(monday);
  const [y,m] = mKey.split("-").map(Number);
  const monthStart = new Date(y,m-1,1), monthEnd = new Date(y,m,0);
  const denom = networkDays(monthStart, monthEnd);
  if(!denom) return 0;
  const wStart = parseDate(monday);
  const wEnd = new Date(wStart); wEnd.setDate(wStart.getDate()+6);
  const today = new Date(); today.setHours(0,0,0,0);
  if(wStart > today) return 0;
  const countEnd = wEnd > today ? today : wEnd;
  return networkDays(wStart, countEnd)/denom;
}
function dayTargetFraction(dateStr){
  const mKey = monthKeyOf(dateStr);
  const [y,m] = mKey.split("-").map(Number);
  const monthStart = new Date(y,m-1,1), monthEnd = new Date(y,m,0);
  const denom = networkDays(monthStart, monthEnd);
  if(!denom) return 0;
  const d = parseDate(dateStr);
  const today = new Date(); today.setHours(0,0,0,0);
  if(d > today) return 0;
  const dow = d.getDay();
  if(dow===0 || dow===6) return 0;
  return 1/denom;
}

/* ---------------- Aggregation ---------------- */
function emptyAgg(){ return {calls:0,rpcs:0,contacts:0,emailsSent:0,emailsOpened:0,demosSet:0,scheduled:0,held:0,closedWon:0,arr:0}; }
function sumRows(rows){
  const a = emptyAgg();
  for(const r of rows){ a.calls+=r.calls; a.rpcs+=r.rpcs; a.contacts+=r.contacts; a.emailsSent+=r.emailsSent;
    a.emailsOpened+=r.emailsOpened; a.demosSet+=r.demosSet; a.scheduled+=r.scheduled; a.held+=r.held;
    a.closedWon+=r.closedWon; a.arr+=r.arr; }
  return a;
}
function deriveRates(a){
  return Object.assign({}, a, {
    rpcConnectRate: a.calls? a.rpcs/a.calls : null,
    rpcToDemoRate: a.rpcs? a.demosSet/a.rpcs : null,
    showingRate: a.scheduled? a.held/a.scheduled : null,
    saleConversionRate: a.held? a.closedWon/a.held : null
  });
}
function rowsForMonth(brand, mKey){ return getAllRows(brand).filter(r=>monthKeyOf(r.date)===mKey); }
function rowsForWeek(brand, monday){ return getAllRows(brand).filter(r=>mondayOf(r.date)===monday); }
function rowsForDay(brand, dateStr){ return getAllRows(brand).filter(r=>r.date===dateStr); }

function uniqueMonths(brand){ return Array.from(new Set(getAllRows(brand).map(r=>monthKeyOf(r.date)))).sort(); }
function uniqueWeeks(brand){ return Array.from(new Set(getAllRows(brand).map(r=>mondayOf(r.date)))).sort(); }
function uniqueDays(brand){ return Array.from(new Set(getAllRows(brand).map(r=>r.date))).sort(); }
// Latest date present across both brands' data (embedded + any extra rows). Used to
// detect "new data just landed" so the Day/Week/Month pickers can snap forward to it
// instead of staying stuck on whatever a user last clicked.
function globalMaxDay(){
  const days = uniqueDays("SM").concat(uniqueDays("TT"));
  return days.length ? days.reduce((a,b)=> b>a?b:a) : null;
}
// If the newest date in the data has moved on since the last time this dashboard was
// opened (i.e. we just pushed a fresh pull), forget the pinned Day/Week/Month selections
// so every tab falls back to its "most recent" default instead of showing a stale date.
function syncFreshness(){
  const maxDay = globalMaxDay();
  if(!maxDay) return;
  const ui = loadJSON(LS.ui, {});
  if(ui.seenMaxDay !== maxDay){
    delete ui.sum_day; delete ui.sum_week; delete ui.sum_month;
    ui.seenMaxDay = maxDay;
    saveJSON(LS.ui, ui);
  }
}

/* ---------------- Formatting ---------------- */
function fmtMetric(key, val){
  if(val===null || val===undefined || isNaN(val)) return "-";
  if(RATE_METRICS.has(key)) return (val*100).toFixed(1)+"%";
  if(MONEY_METRICS.has(key)) return "$"+Math.round(val).toLocaleString();
  return Math.round(val).toLocaleString();
}
function fmtPct(val){ if(val===null||val===undefined||isNaN(val)) return "-"; return (val*100).toFixed(1)+"%"; }
// Same red/green rule as the Actual column: at or above target is good, below is bad.
function pillClass(pct){ if(pct===null||isNaN(pct)) return "mid"; return pct>=1 ? "good" : "bad"; }

/* ---------------- State ---------------- */
let STATE = { brand: loadJSON(LS.ui, {}).brand || "SM", tab: "summary" };

function saveUI(){ const cur = loadJSON(LS.ui, {}); cur.brand = STATE.brand; saveJSON(LS.ui, cur); }

/* ---------------- Renderers ---------------- */
function periodPickerHTML(id, opts, selected, label){
  return `<div class="field"><label>${label}</label><select id="${id}">${
    opts.map(o=>`<option value="${o.value}" ${o.value===selected?"selected":""}>${o.text}</option>`).join("")
  }</select></div>`;
}

function renderBrandToggle(){
  applyTheme(STATE.brand);
  const el = document.getElementById("brandToggle");
  el.innerHTML = BRANDS.map(b=>`<button data-brand="${b.key}" class="${b.key===STATE.brand?'active':''}">
      <img src="${b.logo}" alt="${b.name}" class="brand-logo-icon">${b.name}
    </button>`).join("");
  el.querySelectorAll("button").forEach(btn=>{
    btn.addEventListener("click", ()=>{ STATE.brand=btn.dataset.brand; saveUI(); renderAll(); });
  });
  const active = BRANDS.find(b=>b.key===STATE.brand);
  const headerLogo = document.getElementById("headerLogo");
  if(headerLogo){ headerLogo.src = active.logo; headerLogo.alt = active.name; }
}

function renderTabs(){
  document.querySelectorAll(".tab-btn").forEach(btn=>{
    btn.classList.toggle("active", btn.dataset.tab===STATE.tab);
    btn.onclick = ()=>{ STATE.tab=btn.dataset.tab; renderAll(); };
  });
  document.querySelectorAll(".panel").forEach(p=>{
    p.classList.toggle("active", p.id==="panel-"+STATE.tab);
  });
}

// Top KPI cards are grouped into three rows: outcomes, rates, then activity volume.
// (The Full Breakdown table below keeps its own separate METRIC_ORDER.)
const KPI_ROWS = [
  ["arr","closedWon","demosSet","scheduled","held"],
  ["rpcConnectRate","rpcToDemoRate","showingRate","saleConversionRate"],
  ["calls","rpcs","contacts","emailsSent","emailsOpened"]
];
// Maps a KPI card's metric key to its matching row on the Data (Targets) tab, so the
// Monthly/Weekly/Daily Summary boxes can be colored against the same monthly target.
// Metrics with no entry here (calls, rpcs, contacts, emails, saleConversionRate) have no
// target and stay uncolored.
const METRIC_TARGET_KEY = {closedWon:"wonTarget", arr:"revenue", held:"demoHeld", demosSet:"demoSet",
  showingRate:"showingRate", rpcConnectRate:"rpcConnectRate", rpcToDemoRate:"rpcToDemoRate"};
// targetFrac is the fraction of the full monthly target this specific period (month/week/day)
// should be measured against (see monthProration/weekTargetFraction/dayTargetFraction) --
// pass brand+targetFrac to color cards green/red; omit either to leave cards uncolored.
function kpiGrid(agg, brand, targetFrac){
  const rates = deriveRates(agg);
  const targets = brand ? DEFAULT_TARGETS[brand] : null;
  return KPI_ROWS.map(row => `<div class="kpi-grid">` + row.map(k=>{
    const val = RATE_METRICS.has(k) ? rates[k] : agg[k];
    let cls = "";
    const tKey = METRIC_TARGET_KEY[k];
    if(targets && tKey && targetFrac!==undefined){
      const periodTarget = (targets[tKey]||0) * targetFrac;
      if(periodTarget){
        cls = (val!==null && val!==undefined && !isNaN(val) && val>=periodTarget) ? "metric-good" : "metric-bad";
      }
    }
    return `<div class="kpi"><div class="label">${METRIC_LABEL[k]}</div><div class="value ${cls}">${fmtMetric(k,val)}</div></div>`;
  }).join("") + `</div>`).join("");
}

function metricTable(agg){
  const rates = deriveRates(agg);
  return `<table><tbody>` + METRIC_ORDER.map(k=>{
    const val = RATE_METRICS.has(k) ? rates[k] : agg[k];
    return `<tr><td class="lbl">${METRIC_LABEL[k]}</td><td class="num">${fmtMetric(k,val)}</td></tr>`;
  }).join("") + `</tbody></table>`;
}

/* ---- SUMMARY TAB ----
   Month/Week/Day selections here are shared across both brands (not per-brand),
   so switching the brand toggle keeps whatever period you were looking at. If that
   exact date/week/month doesn't exist in the other brand's data, we snap to the
   closest one that does. */
function nearestDate(target, list){
  if(!list.length) return target;
  if(list.includes(target)) return target;
  const t = parseDate(target);
  let best = list[0], bestDiff = Infinity;
  for(const v of list){ const diff = Math.abs(parseDate(v) - t); if(diff < bestDiff){ bestDiff = diff; best = v; } }
  return best;
}
function nearestMonth(target, list){
  if(!list.length) return target;
  if(list.includes(target)) return target;
  const [ty,tm] = target.split("-").map(Number); const t = new Date(ty, tm-1, 1);
  let best = list[0], bestDiff = Infinity;
  for(const v of list){ const [y,m] = v.split("-").map(Number); const diff = Math.abs(new Date(y,m-1,1) - t); if(diff < bestDiff){ bestDiff = diff; best = v; } }
  return best;
}
// Day/Week/Month are each one single shared value -- across Summary, Monthly/Weekly/Daily
// Summary, Agent Summary, and Data (Targets), AND across both brands. Picking any of them
// on any tab, for either brand, moves everything else to match: a Day implies its Week and
// Month, a Week implies its Month, and an explicit Month pick also snaps Day/Week to its 1st.
function broadcastDay(ui, newDay){
  ui["sum_day"] = newDay;
  ui["sum_week"] = mondayOf(newDay);
  ui["sum_month"] = monthKeyOf(newDay);
}
function broadcastWeek(ui, newWeek){
  ui["sum_week"] = newWeek;
  ui["sum_month"] = monthKeyOf(newWeek);
}
function broadcastMonth(ui, monthKey, resetDayWeek){
  ui["sum_month"] = monthKey;
  if(resetDayWeek){
    const firstOfMonth = monthKey+"-01";
    ui["sum_day"] = firstOfMonth;
    ui["sum_week"] = mondayOf(firstOfMonth);
  }
}
function renderSummary(){
  const brand = STATE.brand;
  const months = uniqueMonths(brand), weeks = uniqueWeeks(brand), days = uniqueDays(brand);
  const ui = loadJSON(LS.ui, {});
  const sMonth = nearestMonth(ui["sum_month"] || currentMonthKey(), months);
  const sWeek = nearestDate(ui["sum_week"] || mondayOf(todayStr()), weeks);
  const sDay = nearestDate(ui["sum_day"] || todayStr(), days);

  const mAgg = sumRows(rowsForMonth(brand, sMonth));
  const wAgg = sumRows(rowsForWeek(brand, sWeek));
  const dAgg = sumRows(rowsForDay(brand, sDay));

  const html = `
  <div class="card">
    <div class="row">
      ${periodPickerHTML("sumMonthPick", months.map(m=>({value:m,text:monthLabel(m)})), sMonth, "Month")}
      ${periodPickerHTML("sumWeekPick", weeks.map(w=>({value:w,text:weekLabel(w)})), sWeek, "Week")}
      ${periodPickerHTML("sumDayPick", days.map(d=>({value:d,text:fmtDate(d)})), sDay, "Day")}
    </div>
    <div style="overflow-x:auto;">
    <table class="cmp-table">
      <colgroup><col class="label-col"><col><col><col></colgroup>
      <thead><tr><th class="lbl"></th><th class="num">Monthly</th><th class="num">Weekly</th><th class="num">Daily</th></tr></thead>
      <tbody>
        ${METRIC_ORDER.map(k=>{
          const mR = deriveRates(mAgg), wR = deriveRates(wAgg), dR = deriveRates(dAgg);
          const mv = RATE_METRICS.has(k)?mR[k]:mAgg[k], wv = RATE_METRICS.has(k)?wR[k]:wAgg[k], dv = RATE_METRICS.has(k)?dR[k]:dAgg[k];
          return `<tr><td class="lbl">${METRIC_LABEL[k]}</td><td class="num">${fmtMetric(k,mv)}</td><td class="num">${fmtMetric(k,wv)}</td><td class="num">${fmtMetric(k,dv)}</td></tr>`;
        }).join("")}
      </tbody>
    </table>
    </div>
  </div>
  <div class="card">
    <h3>Weekly Trend &mdash; Calls Placed &amp; RPCs (last 10 weeks)</h3>
    <canvas id="trendChart"></canvas>
  </div>
  <div class="card">
    <h3>Weekly Trend &mdash; RPC to Demo Conversion Rate (last 10 weeks)</h3>
    <canvas id="rateTrendChart"></canvas>
  </div>`;
  document.getElementById("panel-summary").innerHTML = html;

  // Picking any period here also moves Monthly/Weekly/Daily Summary, Agent Summary, and
  // Data (Targets) to match -- Day/Week/Month are each one shared value everywhere.
  document.getElementById("sumMonthPick").onchange = e=>{
    broadcastMonth(ui, e.target.value, true);
    saveJSON(LS.ui,ui); renderSummary();
  };
  document.getElementById("sumWeekPick").onchange = e=>{
    broadcastWeek(ui, e.target.value);
    saveJSON(LS.ui,ui); renderSummary();
  };
  document.getElementById("sumDayPick").onchange = e=>{
    broadcastDay(ui, e.target.value);
    saveJSON(LS.ui,ui);
    renderSummary();
  };

  drawTrendChart(brand, weeks);
  drawRateTrendChart(brand, weeks);
}

let trendChartInstance = null;
function drawTrendChart(brand, weeks){
  const last = weeks.slice(-10);
  const calls = last.map(w=>sumRows(rowsForWeek(brand,w)).calls);
  const rpcs = last.map(w=>sumRows(rowsForWeek(brand,w)).rpcs);
  const ctx = document.getElementById("trendChart");
  if(!ctx) return;
  if(trendChartInstance){ trendChartInstance.destroy(); }
  const brandColor = (BRANDS.find(b=>b.key===brand) || BRANDS[0]).theme.chart;
  trendChartInstance = new Chart(ctx, {
    type:"line",
    data:{ labels: last.map(w=>fmtDate(w)),
      datasets:[
        {label:"Calls Placed", data:calls, borderColor:brandColor, backgroundColor:brandColor, tension:.3},
        {label:"RPCs", data:rpcs, borderColor:"#16a34a", backgroundColor:"#16a34a", tension:.3, yAxisID:"y1"}
      ]},
    options:{ responsive:true, maintainAspectRatio:false,
      scales:{ y:{beginAtZero:true}, y1:{beginAtZero:true, position:"right", grid:{drawOnChartArea:false}} } }
  });
}

let rateTrendChartInstance = null;
function drawRateTrendChart(brand, weeks){
  const last = weeks.slice(-10);
  const rate = last.map(w=>{
    const agg = sumRows(rowsForWeek(brand,w));
    return agg.rpcs ? (agg.demosSet/agg.rpcs)*100 : null;
  });
  const ctx = document.getElementById("rateTrendChart");
  if(!ctx) return;
  if(rateTrendChartInstance){ rateTrendChartInstance.destroy(); }
  const brandColor = (BRANDS.find(b=>b.key===brand) || BRANDS[0]).theme.chart;
  rateTrendChartInstance = new Chart(ctx, {
    type:"line",
    data:{ labels: last.map(w=>fmtDate(w)),
      datasets:[
        {label:"RPC to Demo Conversion Rate", data:rate, borderColor:brandColor, backgroundColor:brandColor, tension:.3, spanGaps:true}
      ]},
    options:{ responsive:true, maintainAspectRatio:false,
      scales:{ y:{beginAtZero:true, ticks:{callback:v=>v+"%"}} },
      plugins:{ tooltip:{ callbacks:{ label:ctx=> ctx.dataset.label+": "+(ctx.parsed.y===null?"-":ctx.parsed.y.toFixed(1)+"%") } } } }
  });
}

/* ---- MONTHLY / WEEKLY / DAILY (single period) TABS ---- */
function renderPeriodTab(tabKey, unitLabel, pickerBuilder){
  const brand = STATE.brand;
  const ui = loadJSON(LS.ui, {});
  const {opts, selected, rowsFn, uiKey, onSelect, targetFrac} = pickerBuilder(brand, ui);
  const agg = sumRows(rowsFn(selected));
  const html = `
  <div class="card">
    <div class="row">${periodPickerHTML(tabKey+"Pick", opts, selected, unitLabel)}</div>
    <h3>${unitLabel}: ${opts.find(o=>o.value===selected)?.text || ""}</h3>
    ${kpiGrid(agg, brand, targetFrac)}
  </div>
  <div class="card"><h3>Full Breakdown</h3>${metricTable(agg)}</div>`;
  document.getElementById("panel-"+tabKey).innerHTML = html;
  document.getElementById(tabKey+"Pick").onchange = e=>{
    const val = e.target.value;
    ui[uiKey] = val;
    if(onSelect) onSelect(ui, val);
    saveJSON(LS.ui,ui);
    renderAll();
  };
}

function renderMonthly(){
  renderPeriodTab("monthly","Month",(brand,ui)=>{
    const months = uniqueMonths(brand);
    // Month/Week/Day are each one shared value used everywhere, for both brands -- not
    // per-brand keys -- so picking one here also moves Summary, Weekly/Daily Summary,
    // Agent Summary, Data (Targets), and the other brand to match.
    const uiKey = "sum_month";
    const selected = ui[uiKey] && months.includes(ui[uiKey]) ? ui[uiKey] : (months.includes(currentMonthKey())?currentMonthKey():months[months.length-1]);
    const onSelect = (ui, val) => broadcastMonth(ui, val, true);
    return {opts: months.map(m=>({value:m,text:monthLabel(m)})), selected, rowsFn:(m)=>rowsForMonth(brand,m), uiKey, onSelect, targetFrac: monthProration(selected)};
  });
}
function renderWeekly(){
  renderPeriodTab("weekly","Week",(brand,ui)=>{
    const weeks = uniqueWeeks(brand);
    const uiKey = "sum_week";
    const curWeek = mondayOf(todayStr());
    const selected = ui[uiKey] && weeks.includes(ui[uiKey]) ? ui[uiKey] : (weeks.includes(curWeek)?curWeek:weeks[weeks.length-1]);
    const onSelect = (ui, val) => broadcastWeek(ui, val);
    return {opts: weeks.map(w=>({value:w,text:weekLabel(w)})), selected, rowsFn:(w)=>rowsForWeek(brand,w), uiKey, onSelect, targetFrac: weekTargetFraction(selected)};
  });
}
function renderDaily(){
  renderPeriodTab("daily","Day",(brand,ui)=>{
    const days = uniqueDays(brand);
    const uiKey = "sum_day";
    const selected = ui[uiKey] && days.includes(ui[uiKey]) ? ui[uiKey] : (days.includes(todayStr())?todayStr():days[days.length-1]);
    const onSelect = (ui, val) => broadcastDay(ui, val);
    return {opts: days.map(d=>({value:d,text:fmtDate(d)})), selected, rowsFn:(d)=>rowsForDay(brand,d), uiKey, onSelect, targetFrac: dayTargetFraction(selected)};
  });
}

/* ---- AGENT SUMMARY TAB ---- */
const AGENT_COLS = ["calls","rpcs","rpcConnectRate","contacts","emailsSent","emailsOpened","demosSet","scheduled","held","rpcToDemoRate","showingRate","closedWon","saleConversionRate","arr"];
const AGENT_LABEL = {calls:"Calls Placed",rpcs:"RPCs",rpcConnectRate:"Connect Rate",contacts:"Contacts",
  emailsSent:"Emails Sent",emailsOpened:"Emails Opened",demosSet:"Demos Set",scheduled:"Scheduled To Show",
  held:"Held Demo",rpcToDemoRate:"RPC Conv. Rate",showingRate:"Showing Rate",closedWon:"Closed Won",
  saleConversionRate:"Sale Conv. Rate",arr:"ARR"};

function agentTable(rows){
  const byAgent = {};
  rows.forEach(r=>{ (byAgent[r.bdr] = byAgent[r.bdr]||[]).push(r); });
  const names = Object.keys(byAgent).sort();
  if(!names.length) return `<p class="muted small">No data for this period.</p>`;
  return `<div style="overflow-x:auto;"><table><thead><tr><th class="lbl nowrap">BDR</th>${AGENT_COLS.map(k=>`<th class="num nowrap">${AGENT_LABEL[k]}</th>`).join("")}</tr></thead><tbody>
    ${names.map(n=>{
      const agg = deriveRates(sumRows(byAgent[n]));
      return `<tr><td class="lbl nowrap">${n}</td>${AGENT_COLS.map(k=>`<td class="num">${fmtMetric(k,agg[k])}</td>`).join("")}</tr>`;
    }).join("")}
  </tbody></table></div>`;
}

function renderAgent(){
  const brand = STATE.brand;
  const ui = loadJSON(LS.ui, {});
  const months = uniqueMonths(brand), weeks = uniqueWeeks(brand), days = uniqueDays(brand);
  // Day/Week/Month are the shared sum_day/sum_week/sum_month values -- same across
  // every tab and both brands.
  const mSel = ui["sum_month"] && months.includes(ui["sum_month"]) ? ui["sum_month"] : (months.includes(currentMonthKey())?currentMonthKey():months[months.length-1]);
  const wSel = ui["sum_week"] && weeks.includes(ui["sum_week"]) ? ui["sum_week"] : (weeks.includes(mondayOf(todayStr()))?mondayOf(todayStr()):weeks[weeks.length-1]);
  const dSel = ui["sum_day"] && days.includes(ui["sum_day"]) ? ui["sum_day"] : (days.includes(todayStr())?todayStr():days[days.length-1]);

  const html = `
  <div class="card">
    <div class="row">${periodPickerHTML("agentDayPick", days.map(d=>({value:d,text:fmtDate(d)})), dSel, "Day")}</div>
    <h3>Daily &mdash; ${fmtDate(dSel)}</h3>
    ${agentTable(rowsForDay(brand,dSel))}
  </div>
  <div class="card">
    <div class="row">${periodPickerHTML("agentWeekPick", weeks.map(w=>({value:w,text:weekLabel(w)})), wSel, "Week")}</div>
    <h3>${weekLabel(wSel)}</h3>
    ${agentTable(rowsForWeek(brand,wSel))}
  </div>
  <div class="card">
    <div class="row">${periodPickerHTML("agentMonthPick", months.map(m=>({value:m,text:monthLabel(m)})), mSel, "Month")}</div>
    <h3>${monthLabel(mSel)}</h3>
    ${agentTable(rowsForMonth(brand,mSel))}
  </div>`;
  document.getElementById("panel-agent").innerHTML = html;
  // These three pickers drive (and follow) the same shared Day/Week/Month used by
  // Summary, Monthly/Weekly/Daily Summary, and Data (Targets), for both brands.
  document.getElementById("agentDayPick").onchange = e=>{
    broadcastDay(ui, e.target.value);
    saveJSON(LS.ui,ui);
    renderAgent();
  };
  document.getElementById("agentWeekPick").onchange = e=>{
    broadcastWeek(ui, e.target.value);
    saveJSON(LS.ui,ui); renderAgent();
  };
  document.getElementById("agentMonthPick").onchange = e=>{
    broadcastMonth(ui, e.target.value, true);
    saveJSON(LS.ui,ui); renderAgent();
  };
}

/* ---- DATA (TARGETS) TAB ---- */
const TARGET_ROWS = [
  {key:"wonTarget", label:"Won Target (count)", type:"count", actual:a=>a.closedWon},
  {key:"revenue", label:"Revenue ($)", type:"money", actual:a=>a.arr},
  {key:"demoHeld", label:"Demo Held", type:"count", actual:a=>a.held},
  {key:"demoSet", label:"Demo Set", type:"count", actual:a=>a.demosSet},
  {key:"showingRate", label:"Showing Rate", type:"rate", actual:a=>deriveRates(a).showingRate},
  {key:"rpcConnectRate", label:"RPC Connect Rate", type:"rate", actual:a=>deriveRates(a).rpcConnectRate},
  {key:"rpcToDemoRate", label:"RPC to Demo Conversion Rate", type:"rate", actual:a=>deriveRates(a).rpcToDemoRate}
];
const PRORATED_KEYS = new Set(["wonTarget","revenue","demoHeld","demoSet"]);

// Targets are fixed values set by whoever manages the dashboard (not user-editable in the
// UI) -- DEFAULT_TARGETS is the single source of truth, currently seeded with July's numbers.
// To change a month's targets, update DEFAULT_TARGETS in the data and rebuild.
function renderData(){
  const brand = STATE.brand;
  const ui = loadJSON(LS.ui, {});
  const months = uniqueMonths(brand);
  const allMonthOptions = Array.from(new Set(months.concat([currentMonthKey()]))).sort();
  // Month is the shared sum_month value (see broadcastMonth) -- same across both brands.
  const mSel = ui["sum_month"] && allMonthOptions.includes(ui["sum_month"]) ? ui["sum_month"] : currentMonthKey();
  const targets = DEFAULT_TARGETS[brand] || {wonTarget:0, revenue:0, demoHeld:0, demoSet:0, showingRate:0, rpcConnectRate:0, rpcToDemoRate:0};
  const agg = sumRows(rowsForMonth(brand, mSel));
  const prorate = monthProration(mSel);
  const brandName = BRANDS.find(b=>b.key===brand).name;

  const rowsHtml = TARGET_ROWS.map(tr=>{
    const target = targets[tr.key] || 0;
    const mtd = PRORATED_KEYS.has(tr.key) ? target*prorate : target;
    const actual = tr.actual(agg);
    const perf = target ? (actual/target) : null;
    const fmt = v => tr.type==="rate" ? fmtPct(v) : tr.type==="money" ? "$"+Math.round(v).toLocaleString() : Math.round(v).toLocaleString();
    // Actual is colored green when it has met/exceeded the MTD target, red when it hasn't.
    const metMTD = mtd ? (actual >= mtd) : null;
    const actualClass = metMTD===null ? "" : metMTD ? "metric-good" : "metric-bad";
    return `<tr>
      <td class="lbl">${tr.label}</td>
      <td class="num">${fmt(target)}</td>
      <td class="num">${fmt(mtd)}</td>
      <td class="num ${actualClass}">${fmt(actual)}</td>
      <td class="num"><span class="pill ${pillClass(perf)}">${fmtPct(perf)}</span></td>
    </tr>`;
  }).join("");

  document.getElementById("panel-data").innerHTML = `
  <div class="card">
    <div class="row">
      ${periodPickerHTML("dataMonthPick", allMonthOptions.map(m=>({value:m,text:monthLabel(m)})), mSel, "Month")}
    </div>
    <h3>${monthLabel(mSel)} &mdash; ${brandName} Performance Table</h3>
    <table>
      <thead><tr><th class="lbl">Metric</th><th class="num">Target</th><th class="num">${mSel===currentMonthKey()?"MTD Target":"Month Target"}</th><th class="num">Actual</th><th class="num">Performance</th></tr></thead>
      <tbody>${rowsHtml}</tbody>
    </table>
    <p class="hint">Targets are fixed and prorate against business days elapsed for MTD comparisons. To change a target, send the new numbers and it'll be updated here.</p>
  </div>`;

  document.getElementById("dataMonthPick").onchange = e=>{
    broadcastMonth(ui, e.target.value, true);
    saveJSON(LS.ui,ui); renderData();
  };
}

/* ---- ADD DATA TAB ---- */
function renderAdd(){
  const brand = STATE.brand;
  const bdrs = allBdrs(brand);
  const extra = getExtraRows(brand).slice().reverse();
  document.getElementById("panel-add").innerHTML = `
  <div class="card">
    <h3>Add a Daily Entry &mdash; ${BRANDS.find(b=>b.key===brand).name}</h3>
    <div class="entry-form">
      <div class="field"><label>Date</label><input type="date" id="f_date" value="${todayStr()}"></div>
      <div class="field"><label>BDR</label>
        <select id="f_bdr_select"><option value="__new__">+ New BDR...</option>${bdrs.map(b=>`<option value="${b}">${b}</option>`).join("")}</select>
      </div>
      <div class="field" id="f_bdr_new_wrap" style="display:none;"><label>New BDR Name</label><input type="text" id="f_bdr_new" placeholder="Full name"></div>
      <div class="field"><label>Calls Placed</label><input type="number" id="f_calls" value="0"></div>
      <div class="field"><label>RPCs</label><input type="number" id="f_rpcs" value="0"></div>
      <div class="field"><label>Contacts</label><input type="number" id="f_contacts" value="0"></div>
      <div class="field"><label>Emails Sent</label><input type="number" id="f_emailsSent" value="0"></div>
      <div class="field"><label>Emails Opened</label><input type="number" id="f_emailsOpened" value="0"></div>
      <div class="field"><label>Demos Set</label><input type="number" id="f_demosSet" value="0"></div>
      <div class="field"><label>Scheduled To Show</label><input type="number" id="f_scheduled" value="0"></div>
      <div class="field"><label>Held Demo</label><input type="number" id="f_held" value="0"></div>
      <div class="field"><label>Closed Won</label><input type="number" id="f_closedWon" value="0"></div>
      <div class="field"><label>ARR ($)</label><input type="number" id="f_arr" value="0"></div>
    </div>
    <div style="margin-top:14px;"><button class="btn" id="addEntryBtn">Add Entry</button></div>
  </div>
  <div class="card">
    <h3>Entries Added Here (${extra.length})</h3>
    ${extra.length? `<div style="overflow-x:auto;"><table><thead><tr><th class="lbl nowrap">Date</th><th class="lbl nowrap">BDR</th><th class="num">Calls</th><th class="num">RPCs</th><th class="num">Contacts</th><th class="num">Emails Sent</th><th class="num">Opened</th><th class="num">Demos Set</th><th class="num">Sched.</th><th class="num">Held</th><th class="num">Won</th><th class="num">ARR</th><th></th></tr></thead><tbody>
      ${extra.map(r=>`<tr><td class="lbl nowrap">${fmtDate(r.date)}</td><td class="lbl nowrap">${r.bdr}</td><td class="num">${r.calls}</td><td class="num">${r.rpcs}</td><td class="num">${r.contacts}</td><td class="num">${r.emailsSent}</td><td class="num">${r.emailsOpened}</td><td class="num">${r.demosSet}</td><td class="num">${r.scheduled}</td><td class="num">${r.held}</td><td class="num">${r.closedWon}</td><td class="num">$${r.arr}</td><td><button class="btn danger" data-id="${r.id}">Delete</button></td></tr>`).join("")}
    </tbody></table></div>` : `<p class="muted small">No manually-added entries yet. Rows added here supplement the historical HubSpot export baked into this dashboard.</p>`}
  </div>`;

  const sel = document.getElementById("f_bdr_select");
  sel.onchange = ()=>{ document.getElementById("f_bdr_new_wrap").style.display = sel.value==="__new__"?"flex":"none"; };

  document.getElementById("addEntryBtn").onclick = ()=>{
    const bdrName = sel.value==="__new__" ? document.getElementById("f_bdr_new").value.trim() : sel.value;
    if(!bdrName){ showToast("Enter a BDR name"); return; }
    const row = {
      id: Date.now()+"_"+Math.random().toString(36).slice(2,7),
      date: document.getElementById("f_date").value || todayStr(),
      bdr: bdrName,
      calls: parseFloat(document.getElementById("f_calls").value)||0,
      rpcs: parseFloat(document.getElementById("f_rpcs").value)||0,
      contacts: parseFloat(document.getElementById("f_contacts").value)||0,
      emailsSent: parseFloat(document.getElementById("f_emailsSent").value)||0,
      emailsOpened: parseFloat(document.getElementById("f_emailsOpened").value)||0,
      demosSet: parseFloat(document.getElementById("f_demosSet").value)||0,
      scheduled: parseFloat(document.getElementById("f_scheduled").value)||0,
      held: parseFloat(document.getElementById("f_held").value)||0,
      closedWon: parseFloat(document.getElementById("f_closedWon").value)||0,
      arr: parseFloat(document.getElementById("f_arr").value)||0
    };
    const rows = getExtraRows(brand); rows.push(row); setExtraRows(brand, rows);
    invalidateCache(brand);
    showToast("Entry added for "+bdrName);
    renderAll();
  };

  document.querySelectorAll("[data-id]").forEach(btn=>{
    btn.onclick = ()=>{
      const rows = getExtraRows(brand).filter(r=>r.id!==btn.dataset.id);
      setExtraRows(brand, rows); invalidateCache(brand); renderAll();
    };
  });
}

