const SOURCE_STATUS_LABEL = {auto:"good", partial:"mid", manual:"bad"};
function renderSources(){
  document.getElementById("panel-sources").innerHTML = `
  <div class="card">
    <h3>How This Dashboard Gets Its Data</h3>
    <p class="hint">A running log of where each metric comes from and how it's pulled -- updated as the process changes, so this always reflects what's actually happening, not just how things started.</p>
  </div>
  ${SOURCE_NOTES.map((s,i)=>`
    <div class="card">
      <h3>${i+1}. ${s.metric} <span class="pill ${SOURCE_STATUS_LABEL[s.status]}" style="margin-left:8px;">${s.statusLabel}</span></h3>
      <p class="hint" style="margin-top:0;"><strong>Source:</strong> ${s.report}</p>
      <div class="section-title">How it's pulled</div>
      <ul style="margin:0 0 10px;padding-left:20px;">${s.how.map(h=>`<li style="margin-bottom:4px;">${h}</li>`).join("")}</ul>
      ${s.why && s.why.length ? `<div class="section-title">${s.status==="manual" ? "Why this can't be automated" : "Why this uses browser automation, not a direct API query"}</div>
      <ul style="margin:0 0 10px;padding-left:20px;">${s.why.map(w=>`<li style="margin-bottom:4px;">${w}</li>`).join("")}</ul>` : ""}
      ${s.notes && s.notes.length ? `<div class="section-title">Notes</div>
      <ul style="margin:0;padding-left:20px;">${s.notes.map(n=>`<li style="margin-bottom:4px;">${n}</li>`).join("")}</ul>` : ""}
    </div>
  `).join("")}
  <div class="card">
    <h3>Standing Rules (apply to every metric)</h3>
    <ul style="margin:0;padding-left:20px;">
      <li style="margin-bottom:4px;">Never include today or future-dated entries -- only capture data through yesterday.</li>
      <li style="margin-bottom:4px;">When a report covers the whole month, treat it as authoritative for that period: replace existing values for that month, don't just add to them.</li>
      <li style="margin-bottom:4px;">Only the active roster gets data corrections/additions; historical/departed BDRs stay frozen at their original baseline.</li>
      <li style="margin-bottom:4px;">Renecille Grace Mojado left the active roster effective 2026-07-02. All her data from that date onward was removed (not just frozen) per Sap's request; her pre-July-2 historical rows remain untouched. Her name stays in the "bdrs" index array in sm_compact.json purely to keep other BDRs' row indices stable -- never remove or reorder that array -- but she is excluded from every automated pull's active roster going forward and should not be re-added.</li>
      <li style="margin-bottom:4px;">Known name aliases between HubSpot and the dashboard roster: Ice Crisolo &rarr; Aileen Crisolo (SM), Brian Morales &rarr; Ian Bitor (SM), Mico Garcia &rarr; Micco Jargue (SM), Maria Cecilia Rey &rarr; Cecilia Rey (TT). All other names map 1:1.</li>
      <li style="margin-bottom:4px;">If a metric (or a specific detail of how it's pulled) has been explicitly discussed and decided to stay manual, it stays manual -- do not automate it, change its status, or overlap it with an automated pull until Sap explicitly says to revisit it.</li>
    </ul>
  </div>`;
}

/* ---------------- Toast ---------------- */
let toastTimer=null;
function showToast(msg){
  const t = document.getElementById("toast");
  t.textContent = msg; t.classList.add("show");
  clearTimeout(toastTimer);
  toastTimer = setTimeout(()=>t.classList.remove("show"), 2200);
}

/* ---------------- Master render ---------------- */
function renderAll(){
  renderBrandToggle();
  renderTabs();
  if(STATE.tab==="summary") renderSummary();
  else if(STATE.tab==="monthly") renderMonthly();
  else if(STATE.tab==="weekly") renderWeekly();
  else if(STATE.tab==="daily") renderDaily();
  else if(STATE.tab==="agent") renderAgent();
  else if(STATE.tab==="data") renderData();
  else if(STATE.tab==="add") renderAdd();
  else if(STATE.tab==="sources") renderSources();
}
syncFreshness();
renderAll();
